#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int D;
        scanf("%d", &D);
        int problems[D + 1] = {0};
        for (int i = 0; i < D; i++) {
            int di, pi;
            scanf("%d %d", &di, &pi);
            problems[di] = pi;
        }
        int Q;
        scanf("%d", &Q);
        while (Q--) {
            int deadi, reqi;
            scanf("%d %d", &deadi, &reqi);
            int total = 0;
            for (int i = 1; i <= deadi; i++) {
                total += problems[i];
            }
            if (total >= reqi) {
                printf("Go Camp\n");
            } else {
                printf("Go Sleep\n");
            }
        }
    }
    return 0;
}

