import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int D = sc.nextInt();
            int[] problems = new int[D + 1];
            for (int i = 0; i < D; i++) {
                int di = sc.nextInt();
                int pi = sc.nextInt();
                problems[di] = pi;
            }
            int Q = sc.nextInt();
            while (Q-- > 0) {
                int deadi = sc.nextInt();
                int reqi = sc.nextInt();
                int total = 0;
                for (int i = 1; i <= deadi; i++) {
                    total += problems[i];
                }
                if (total >= reqi) {
                    System.out.println("Go Camp");
                } else {
                    System.out.println("Go Sleep");
                }
            }
        }
    }
}

