const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const D = parseInt(readline());
    const problems = new Array(D + 1).fill(0);
    for (let j = 0; j < D; j++) {
        const [di, pi] = readline().split(' ').map(Number);
        problems[di] = pi;
    }
    const Q = parseInt(readline());
    for (let j = 0; j < Q; j++) {
        const [deadi, reqi] = readline().split(' ').map(Number);
        let total = 0;
        for (let k = 1; k <= deadi; k++) {
            total += problems[k];
        }
        if (total >= reqi) {
            console.log('Go Camp');
        } else {
            console.log('Go Sleep');
        }
    }
}
